draw((0,0)--(-3,3), Arrow);
draw((0,0)--(3,3), Arrow);
draw((0,3)--(-3,0), Arrow);
draw((0,3)--(3,0), Arrow);
label("$A$", (-1.5,1.5), W);
label("$B$", (0,3), N);
label("$C$", (1.5,1.5), E);
label("$D$", (0,0), S);
